/**
 * CardRenderer.js
 * Component-based SVG card renderer.
 *
 * Each section of the card is generated by an independent function that
 * returns an SVG string fragment. The root render() function assembles them.
 *
 * Card canvas: 825 × 1125 px (bleed)
 * Trim:        750 × 1050 px  (origin at 37.5, 37.5)
 * Safe area:   675 × 975 px   (origin at 75, 75)
 */

import { escapeXml, wrapText, toInt, str } from "./Utilities.js";
import { TEMPLATE_REGISTRY } from "./Templates.js";

// ─── Card dimension constants ────────────────────────────────────────────────

export const CARD_W = 825;
export const CARD_H = 1125;

// Trim rect (from bleed edge)
const TRIM_INSET = 37.5;
const TRIM_W = 750;
const TRIM_H = 1050;

// Safe area (from bleed edge)
const SAFE_INSET = 75;
const SAFE_W = 675;
const SAFE_H = 975;

// Inner layout guides (relative to trim origin)
const PADDING = 24;           // horizontal padding inside trim
const INNER_X = TRIM_INSET + PADDING;   // ~61.5
const INNER_W = TRIM_W - PADDING * 2;  // 702

// ─── Layout row positions (absolute Y from top of bleed) ─────────────────────
const Y_HEADER_TOP    = 52;   // top of header band
const Y_HEADER_BOT    = 116;  // bottom of header band
const Y_SCI_NAME      = 128;  // scientific name baseline
const Y_ART_TOP       = 140;  // top of art frame
const Y_ART_BOT       = 510;  // bottom of art frame
const Y_TYPE_TOP      = 515;  // type line top
const Y_TYPE_BOT      = 550;  // type line bottom
const Y_RULES_TOP     = 558;  // rules box top
const Y_RULES_BOT     = 870;  // rules box bottom
const Y_FOOTER_TOP    = 878;  // footer start
const Y_STATS_CENTER  = 1053; // center-Y of stats circles
const STATS_RADIUS    = 36;   // radius of stat circles

// ─── Component renderers ─────────────────────────────────────────────────────

/**
 * Render the card background (frame fill + rounded border matching template).
 * @param {CardData} card
 * @param {TemplateConfig} tpl
 * @returns {string}
 */
function renderBackground(card, tpl) {
  const r = 24; // corner radius
  return `
  <!-- Background -->
  <rect x="${TRIM_INSET}" y="${TRIM_INSET}"
        width="${TRIM_W}" height="${TRIM_H}"
        rx="${r}" ry="${r}"
        fill="${tpl.bgGradient ? `url(#grad_bg)` : tpl.bgColor}"
        stroke="${tpl.borderColor}" stroke-width="3"/>`;
}

/**
 * Render the card header band (name + cost icons).
 * @param {CardData} card
 * @param {TemplateConfig} tpl
 * @returns {string}
 */
function renderHeader(card, tpl) {
  const bandH = Y_HEADER_BOT - Y_HEADER_TOP;
  const nameX = INNER_X;
  const nameY = Y_HEADER_TOP + bandH / 2 + 14; // roughly centered

  // Cost icons: up to 3 types, drawn right-aligned
  const costs = [
    { key: "water",  color: "#3B82F6", label: "W" },
    { key: "flora",  color: "#22C55E", label: "F" },
    { key: "fauna",  color: "#F97316", label: "A" },
  ];
  const costSlots = costs.filter((c) => (card.cost?.[c.key] ?? 0) > 0);
  const iconSize = 28;
  const iconGap = 6;
  let costSvg = "";
  let rightX = TRIM_INSET + TRIM_W - PADDING;

  for (let i = costSlots.length - 1; i >= 0; i--) {
    const c = costSlots[i];
    const val = toInt(card.cost?.[c.key]);
    const cx = rightX - iconSize / 2;
    rightX -= iconSize + iconGap;
    costSvg = `
  <circle cx="${cx}" cy="${Y_HEADER_TOP + bandH / 2}" r="${iconSize / 2}"
          fill="${c.color}" stroke="#fff" stroke-width="1.5"/>
  <text x="${cx}" y="${Y_HEADER_TOP + bandH / 2 + 5}"
        text-anchor="middle" font-family="Georgia,serif" font-size="13"
        font-weight="bold" fill="#fff">${val}</text>` + costSvg;
  }

  return `
  <!-- Header -->
  <rect x="${TRIM_INSET}" y="${Y_HEADER_TOP}"
        width="${TRIM_W}" height="${bandH}"
        fill="${tpl.headerColor}" rx="20" ry="20"/>
  <rect x="${TRIM_INSET}" y="${Y_HEADER_TOP + bandH / 2}"
        width="${TRIM_W}" height="${bandH / 2}"
        fill="${tpl.headerColor}"/>
  <text x="${nameX}" y="${nameY}"
        font-family="Georgia,serif" font-size="22" font-weight="bold"
        fill="${tpl.headerTextColor}">${escapeXml(str(card.name, "Unnamed Card"))}</text>
  ${costSvg}`;
}

/**
 * Render the scientific name and rarity line.
 * @param {CardData} card
 * @param {TemplateConfig} tpl
 * @returns {string}
 */
function renderScientificName(card, tpl) {
  const rarityColor = rarityBadgeColor(card.rarity);
  const sciName = str(card.scientificName);
  return `
  <!-- Scientific Name + Rarity -->
  ${sciName ? `<text x="${INNER_X}" y="${Y_SCI_NAME}"
        font-family="Georgia,serif" font-size="12" font-style="italic"
        fill="${tpl.subTextColor}">${escapeXml(sciName)}</text>` : ""}
  <text x="${TRIM_INSET + TRIM_W - PADDING}" y="${Y_SCI_NAME}"
        text-anchor="end" font-family="Arial,sans-serif" font-size="11"
        font-weight="bold" fill="${rarityColor}">${escapeXml(str(card.rarity, "Common"))}</text>`;
}

/**
 * Render the art frame rectangle and embedded artwork image.
 * @param {CardData} card
 * @param {TemplateConfig} tpl
 * @returns {string}
 */
function renderArtFrame(card, tpl) {
  const artX = INNER_X;
  const artY = Y_ART_TOP;
  const artW = INNER_W;
  const artH = Y_ART_BOT - Y_ART_TOP;

  let imageEl = "";
  if (card.artwork?.dataUrl) {
    const zoom = Math.max(0.1, card.artwork.zoom ?? 1);
    const panX = card.artwork.panX ?? 0;
    const panY = card.artwork.panY ?? 0;
    const imgW = artW * zoom;
    const imgH = artH * zoom;
    const imgX = artX + (artW - imgW) / 2 + panX;
    const imgY = artY + (artH - imgH) / 2 + panY;
    imageEl = `
  <image href="${escapeXml(card.artwork.dataUrl)}"
         x="${imgX.toFixed(2)}" y="${imgY.toFixed(2)}"
         width="${imgW.toFixed(2)}" height="${imgH.toFixed(2)}"
         preserveAspectRatio="xMidYMid meet"
         clip-path="url(#artClip)"/>`;
  }

  return `
  <!-- Art Frame -->
  <defs>
    <clipPath id="artClip">
      <rect x="${artX}" y="${artY}" width="${artW}" height="${artH}" rx="8"/>
    </clipPath>
  </defs>
  <rect x="${artX}" y="${artY}" width="${artW}" height="${artH}"
        fill="${tpl.artBg}" rx="8" stroke="${tpl.borderColor}" stroke-width="1.5"/>
  ${imageEl}
  ${!card.artwork?.dataUrl ? `<text x="${artX + artW / 2}" y="${artY + artH / 2 + 8}"
        text-anchor="middle" font-family="Arial,sans-serif" font-size="14"
        fill="${tpl.subTextColor}" opacity="0.5">[ Artwork ]</text>` : ""}`;
}

/**
 * Render the type line (category + habitat).
 * @param {CardData} card
 * @param {TemplateConfig} tpl
 * @returns {string}
 */
function renderTypeLine(card, tpl) {
  const midY = Y_TYPE_TOP + (Y_TYPE_BOT - Y_TYPE_TOP) / 2 + 6;
  const catStr = str(card.category);
  const habStr = str(card.habitat);
  const combined = [catStr, habStr].filter(Boolean).join("  —  ");
  return `
  <!-- Type Line -->
  <rect x="${TRIM_INSET}" y="${Y_TYPE_TOP}" width="${TRIM_W}" height="${Y_TYPE_BOT - Y_TYPE_TOP}"
        fill="${tpl.typeBg}"/>
  <text x="${INNER_X}" y="${midY}"
        font-family="Arial,sans-serif" font-size="13" font-weight="bold"
        fill="${tpl.typeTextColor}">${escapeXml(combined || tpl.label)}</text>`;
}

/**
 * Render the rules box (ability, fact, flavor).
 * @param {CardData} card
 * @param {TemplateConfig} tpl
 * @returns {string}
 */
function renderRulesBox(card, tpl) {
  const boxX = INNER_X;
  const boxY = Y_RULES_TOP;
  const boxW = INNER_W;
  const boxH = Y_RULES_BOT - Y_RULES_TOP;

  const maxChars = 56; // approximate chars per line at font-size 13
  const lineH = 17;
  let lines = [];
  let y = boxY + 20;
  const x = boxX + 12;
  let fragments = "";

  function addSection(label, text) {
    if (!str(text)) return;
    const textLines = wrapText(text, maxChars);
    // Label in bold
    fragments += `<text x="${x}" y="${y}" font-family="Arial,sans-serif"
          font-size="12" font-weight="bold" fill="${tpl.rulesLabelColor}">${escapeXml(label)}</text>`;
    y += lineH;
    for (const line of textLines) {
      if (y + lineH > Y_RULES_BOT - 8) break; // don't overflow
      fragments += `<text x="${x}" y="${y}" font-family="Arial,sans-serif"
          font-size="12" fill="${tpl.rulesTextColor}">${escapeXml(line)}</text>`;
      y += lineH;
    }
    y += 4; // section gap
  }

  function addFlavor(text) {
    if (!str(text)) return;
    const textLines = wrapText(text, maxChars);
    fragments += `<line x1="${x}" y1="${y - 2}" x2="${x + boxW - 24}" y2="${y - 2}"
          stroke="${tpl.borderColor}" stroke-width="0.5" opacity="0.4"/>`;
    y += 6;
    for (const line of textLines) {
      if (y + lineH > Y_RULES_BOT - 8) break;
      fragments += `<text x="${x}" y="${y}" font-family="Georgia,serif"
          font-size="11" font-style="italic" fill="${tpl.flavorColor}">${escapeXml(line)}</text>`;
      y += lineH;
    }
  }

  addSection("Ability:", card.text?.ability ?? "");
  addSection("Fact:", card.text?.fact ?? "");
  addFlavor(card.text?.flavor ?? "");

  return `
  <!-- Rules Box -->
  <rect x="${boxX}" y="${boxY}" width="${boxW}" height="${boxH}"
        fill="${tpl.rulesBg}" rx="6" stroke="${tpl.borderColor}" stroke-width="1"/>
  ${fragments}`;
}

/**
 * Render the footer area (expansion, collector number, artist, copyright).
 * @param {CardData} card
 * @param {TemplateConfig} tpl
 * @returns {string}
 */
function renderFooter(card, tpl) {
  const baseY = Y_FOOTER_TOP + 14;
  const rightX = TRIM_INSET + TRIM_W - PADDING;

  return `
  <!-- Footer -->
  <text x="${INNER_X}" y="${baseY}"
        font-family="Arial,sans-serif" font-size="10" fill="${tpl.footerColor}">
        ${escapeXml(str(card.expansion, "ITW-A"))}</text>
  <text x="${INNER_X}" y="${baseY + 13}"
        font-family="Arial,sans-serif" font-size="10" fill="${tpl.footerColor}">
        ${escapeXml(str(card.cardNumber))}</text>
  <text x="${INNER_X + 70}" y="${baseY}"
        font-family="Arial,sans-serif" font-size="10" fill="${tpl.footerColor}">
        Illus. ${escapeXml(str(card.artist))}</text>
  <text x="${rightX}" y="${Y_RULES_BOT + 60}"
        text-anchor="end" font-family="Arial,sans-serif" font-size="9"
        fill="${tpl.footerColor}">${escapeXml(str(card.copyright, "© Into the Wild TCG"))}</text>`;
}

/**
 * Render HP/ATK stat circles at the bottom of the card.
 * @param {CardData} card
 * @param {TemplateConfig} tpl
 * @returns {string}
 */
function renderStats(card, tpl) {
  const hasStats =
    toInt(card.stats?.attack) > 0 ||
    toInt(card.stats?.health) > 0 ||
    toInt(card.stats?.defense) > 0;

  if (!hasStats) return "<!-- No stats -->";

  const cy = Y_STATS_CENTER;
  const r = STATS_RADIUS;
  // Positions: DEF left, ATK center-left, HP center-right
  const cx_atk = TRIM_INSET + TRIM_W / 2 - r - 8;
  const cx_hp  = TRIM_INSET + TRIM_W / 2 + r + 8;
  const cx_def = TRIM_INSET + TRIM_W - PADDING - r;

  function circle(cx, label, value, fillColor) {
    return `
  <circle cx="${cx}" cy="${cy}" r="${r}"
          fill="${fillColor}" stroke="#fff" stroke-width="2.5"/>
  <text x="${cx}" y="${cy - 8}" text-anchor="middle"
        font-family="Arial,sans-serif" font-size="9" font-weight="bold"
        fill="#fff" opacity="0.85">${label}</text>
  <text x="${cx}" y="${cy + 12}" text-anchor="middle"
        font-family="Arial,sans-serif" font-size="19" font-weight="bold"
        fill="#fff">${value}</text>`;
  }

  return `
  <!-- Stats -->
  ${toInt(card.stats?.attack)  > 0 ? circle(cx_atk, "ATK", toInt(card.stats.attack),  "#DC2626") : ""}
  ${toInt(card.stats?.health)  > 0 ? circle(cx_hp,  "HP",  toInt(card.stats.health),  "#16A34A") : ""}
  ${toInt(card.stats?.defense) > 0 ? circle(cx_def, "DEF", toInt(card.stats.defense), "#2563EB") : ""}`;
}

// ─── Gradient helpers ─────────────────────────────────────────────────────────

function renderDefs(tpl) {
  if (!tpl.bgGradient) return "<defs></defs>";
  const [c1, c2] = tpl.bgGradient;
  return `
  <defs>
    <linearGradient id="grad_bg" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="${c1}"/>
      <stop offset="100%" stop-color="${c2}"/>
    </linearGradient>
  </defs>`;
}

// ─── Rarity color lookup ──────────────────────────────────────────────────────

function rarityBadgeColor(rarity) {
  const map = {
    Common: "#9CA3AF",
    Uncommon: "#22C55E",
    Rare: "#3B82F6",
    Epic: "#A855F7",
    Legendary: "#F59E0B",
    Unique: "#EC4899",
  };
  return map[rarity] ?? "#9CA3AF";
}

// ─── Public render function ───────────────────────────────────────────────────

/**
 * Render a complete card SVG string from a CardData object.
 * Guides are NOT included; see SvgRenderer.js for guide-overlay version.
 *
 * @param {CardData} card
 * @returns {string}  Complete SVG document string.
 */
export function renderCard(card) {
  const tpl = TEMPLATE_REGISTRY[card.template] ?? TEMPLATE_REGISTRY.organism;

  const svgParts = [
    `<svg xmlns="http://www.w3.org/2000/svg"
       xmlns:xlink="http://www.w3.org/1999/xlink"
       width="${CARD_W}" height="${CARD_H}"
       viewBox="0 0 ${CARD_W} ${CARD_H}">`,
    renderDefs(tpl),
    renderBackground(card, tpl),
    renderHeader(card, tpl),
    renderScientificName(card, tpl),
    renderArtFrame(card, tpl),
    renderTypeLine(card, tpl),
    renderRulesBox(card, tpl),
    renderFooter(card, tpl),
    renderStats(card, tpl),
    "</svg>",
  ];

  return svgParts.join("\n");
}
